export interface Medicine {
  medicine_name: string;
  medicine_dosage: string;
  frequency: string;
  duration: string;
  instructions: string;
}

export interface DiagnosticTest {
  test_name: string;
}

export interface PatientInfo {
  patient_name: string;
  age: number | string | null;
  gender: 'Male' | 'Female' | 'Other' | null;
  prescription_date: string | null;
}

export interface DoctorInfo {
  doctor_name: string;
  specialization: string | null;
  clinic_name: string;
  contact_info: string | null;
  doctor_signature_present: boolean;
  doctor_stamp_present: boolean;
}

export interface PrescriptionData {
  patient_info: PatientInfo;
  doctor_info: DoctorInfo;
  medical_info: {
    diagnosis_primary: string | null;
    symptoms: string[] | null;
    medicines: Medicine[];
    diagnostics_tests: DiagnosticTest[];
  };
  additional_notes: string | null;
  confidence: 'high' | 'medium' | 'low';
  warnings: string[];
}

export type InputMode = 'upload' | 'url';
export type OutputViewMode = 'structured' | 'json';

import { GoogleGenAI, Type } from "@google/genai";
import { PrescriptionData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

export const prescriptionSchema = {
  type: Type.OBJECT,
  properties: {
    patient_info: {
      type: Type.OBJECT,
      properties: {
        patient_name: { type: Type.STRING },
        age: { type: Type.STRING, nullable: true },
        gender: { type: Type.STRING, nullable: true },
        prescription_date: { type: Type.STRING, nullable: true },
      },
      required: ["patient_name"]
    },
    doctor_info: {
      type: Type.OBJECT,
      properties: {
        doctor_name: { type: Type.STRING },
        specialization: { type: Type.STRING, nullable: true },
        clinic_name: { type: Type.STRING },
        contact_info: { type: Type.STRING, nullable: true },
        doctor_signature_present: { type: Type.BOOLEAN },
        doctor_stamp_present: { type: Type.BOOLEAN },
      },
      required: ["doctor_name", "clinic_name"]
    },
    medical_info: {
      type: Type.OBJECT,
      properties: {
        diagnosis_primary: { type: Type.STRING, nullable: true },
        symptoms: {
          type: Type.ARRAY,
          items: { type: Type.STRING },
          nullable: true
        },
        medicines: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              medicine_name: { type: Type.STRING },
              medicine_dosage: { type: Type.STRING },
              frequency: { type: Type.STRING },
              duration: { type: Type.STRING },
              instructions: { type: Type.STRING },
            },
            required: ["medicine_name"]
          }
        },
        diagnostics_tests: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              test_name: { type: Type.STRING }
            }
          }
        }
      }
    },
    additional_notes: { type: Type.STRING, nullable: true },
    confidence: { type: Type.STRING, description: "One of: high, medium, low" },
    warnings: {
      type: Type.ARRAY,
      items: { type: Type.STRING }
    }
  },
  required: ["patient_info", "doctor_info", "medical_info", "confidence", "warnings"]
};

export async function analyzePrescription(
  base64Data: string,
  mimeType: string
): Promise<PrescriptionData> {
  const model = "gemini-3-flash-preview";

  const response = await ai.models.generateContent({
    model,
    contents: [
      {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
          {
            text: `You are a medical prescription reader AI. Analyze the provided prescription image or PDF carefully.
Extract ALL visible information and return it ONLY as a valid JSON object.

Rules:
- If a field is not visible or not applicable, use null
- For medications, extract every single medicine listed including dosage, frequency, duration, and instructions.
- For handwritten prescriptions, do your best to interpret the handwriting.
- Set "confidence" to "high" if text is clear, "medium" if partially legible, "low" if mostly handwritten and unclear.
- Add any unclear or potentially misread fields to the "warnings" array.
- Do NOT include any text outside the JSON object in your response.`
          },
        ],
      },
    ],
    config: {
      responseMimeType: "application/json",
      responseSchema: prescriptionSchema,
    },
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response from AI model.");
  }

  try {
    return JSON.parse(text) as PrescriptionData;
  } catch (err) {
    console.error("JSON Parsing Error:", err, text);
    throw new Error("Failed to parse the prescription data. The image might be too unclear.");
  }
}

import React, { useState, useRef } from 'react';
import { InputMode } from '../types';

interface InputPanelProps {
  onAnalyze: (base64: string, mimeType: string) => void;
  isLoading: boolean;
  onReset: () => void;
}

const InputPanel: React.FC<InputPanelProps> = ({ onAnalyze, isLoading, onReset }) => {
  const [mode, setMode] = useState<InputMode>('upload');
  const [url, setUrl] = useState('');
  const [preview, setPreview] = useState<string | null>(null);
  const [selectedFile, setSelectedFile] = useState<{ base64: string; mimeType: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      setPreview(reader.result as string);
      setSelectedFile({ base64, mimeType: file.type });
    };
    reader.readAsDataURL(file);
  };

  const handleUrlBlur = async () => {
    if (!url) return;
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        setPreview(reader.result as string);
        setSelectedFile({ base64, mimeType: blob.type });
      };
      reader.readAsDataURL(blob);
    } catch (err) {
      alert("Could not fetch image from URL. CORS or invalid link might be the cause.");
      console.error(err);
    }
  };

  const handleAnalyze = () => {
    if (selectedFile) {
      onAnalyze(selectedFile.base64, selectedFile.mimeType);
    } else {
      alert("Please provide a file or a valid image URL first.");
    }
  };

  const handleResetInternal = () => {
    setPreview(null);
    setSelectedFile(null);
    setUrl('');
    if (fileInputRef.current) fileInputRef.current.value = '';
    onReset();
  };

  return (
    <div className="flex flex-col h-full bg-slate-800/50 p-6 space-y-6">
      <div className="space-y-1">
        <h1 className="text-3xl font-bold text-teal-400 flex items-center gap-2">
          <span>💊</span> MediScan AI
        </h1>
        <p className="text-slate-400 text-sm">Medical Prescription Reader Dashboard</p>
      </div>

      <div className="bg-slate-900 rounded-xl p-1 flex">
        <button
          onClick={() => setMode('upload')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
            mode === 'upload' ? 'bg-teal-600 text-white' : 'text-slate-400 hover:text-slate-200'
          }`}
        >
          📁 Upload File
        </button>
        <button
          onClick={() => setMode('url')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
            mode === 'url' ? 'bg-teal-600 text-white' : 'text-slate-400 hover:text-slate-200'
          }`}
        >
          🔗 Paste URL
        </button>
      </div>

      <div className="flex-1 space-y-4">
        {mode === 'upload' ? (
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="border-2 border-dashed border-slate-700 hover:border-teal-500/50 rounded-xl p-8 flex flex-col items-center justify-center space-y-4 cursor-pointer transition-colors bg-slate-900/30"
          >
            <div className="bg-slate-800 p-4 rounded-full">
              <svg className="w-8 h-8 text-teal-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
            </div>
            <div className="text-center">
              <p className="text-slate-200 font-medium">Click to upload prescription</p>
              <p className="text-slate-500 text-xs mt-1">Supports JPG, PNG, PDF</p>
            </div>
            <input 
              type="file" 
              className="hidden" 
              ref={fileInputRef} 
              accept="image/*,application/pdf"
              onChange={handleFileChange}
            />
          </div>
        ) : (
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Image URL</label>
              <input
                type="text"
                placeholder="https://example.com/prescription.jpg"
                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-slate-200 focus:outline-none focus:ring-2 focus:ring-teal-500/50"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                onBlur={handleUrlBlur}
              />
            </div>
          </div>
        )}

        {preview && (
          <div className="space-y-2">
            <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Preview</label>
            <div className="relative rounded-xl overflow-hidden border border-slate-700 aspect-video bg-black flex items-center justify-center">
              {selectedFile?.mimeType === 'application/pdf' ? (
                <div className="flex flex-col items-center text-slate-400">
                  <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 20 20"><path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z"/></svg>
                  <span>PDF Document</span>
                </div>
              ) : (
                <img src={preview} alt="Preview" className="object-contain w-full h-full" />
              )}
            </div>
          </div>
        )}
      </div>

      <div className="space-y-3">
        <button
          onClick={handleAnalyze}
          disabled={isLoading || !selectedFile}
          className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-3 transition-all ${
            isLoading || !selectedFile
              ? 'bg-slate-700 text-slate-500 cursor-not-allowed'
              : 'bg-gradient-to-r from-teal-600 to-emerald-600 text-white shadow-lg shadow-teal-900/20 hover:scale-[1.02] active:scale-[0.98]'
          }`}
        >
          {isLoading ? (
            <>
              <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              <span>Analyzing...</span>
            </>
          ) : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span>Analyze Prescription</span>
            </>
          )}
        </button>
        <button
          onClick={handleResetInternal}
          className="w-full py-3 text-slate-400 text-sm hover:text-slate-200 transition-colors"
        >
          Clear and Reset
        </button>
      </div>
    </div>
  );
};

export default InputPanel;

import React, { useState } from 'react';
import { PrescriptionData, OutputViewMode } from '../types';
import StructuredView from './StructuredView';

interface OutputPanelProps {
  data: PrescriptionData | null;
  error: string | null;
}

const OutputPanel: React.FC<OutputPanelProps> = ({ data, error }) => {
  const [viewMode, setViewMode] = useState<OutputViewMode>('structured');
  const [copied, setCopied] = useState(false);

  const handleCopyJson = () => {
    if (!data) return;
    navigator.clipboard.writeText(JSON.stringify(data, null, 2));
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-4">
        <div className="bg-red-500/10 p-4 rounded-full text-red-500">
          <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
          </svg>
        </div>
        <h3 className="text-xl font-bold text-white">Analysis Failed</h3>
        <p className="text-slate-400 max-w-md">{error}</p>
      </div>
    );
  }

  if (!data) {
    return (
      <div className="flex flex-col items-center justify-center h-full p-8 text-center space-y-4 text-slate-500">
        <div className="opacity-20">
          <svg className="w-24 h-24" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
          </svg>
        </div>
        <div className="space-y-1">
          <p className="text-lg font-medium text-slate-400">No Analysis Done</p>
          <p className="text-sm">Upload or link a prescription to see extraction results</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full overflow-hidden bg-slate-900/50">
      <div className="p-6 border-b border-slate-800 flex items-center justify-between sticky top-0 bg-slate-900 z-10">
        <h2 className="text-xl font-bold text-white flex items-center gap-2">
          <span className="text-teal-500">📋</span> Extracted Results
        </h2>

        <div className="flex bg-slate-800 p-1 rounded-lg text-xs font-semibold">
          <button
            onClick={() => setViewMode('structured')}
            className={`px-4 py-1.5 rounded-md transition-all ${
              viewMode === 'structured' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'
            }`}
          >
            Structured
          </button>
          <button
            onClick={() => setViewMode('json')}
            className={`px-4 py-1.5 rounded-md transition-all ${
              viewMode === 'json' ? 'bg-slate-700 text-white shadow-sm' : 'text-slate-500 hover:text-slate-300'
            }`}
          >
            JSON
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6">
        {viewMode === 'structured' ? (
          <StructuredView data={data} />
        ) : (
          <div className="relative h-full">
            <button
              onClick={handleCopyJson}
              className="absolute top-4 right-4 bg-slate-800 hover:bg-slate-700 text-slate-300 px-3 py-1.5 rounded-lg text-xs font-medium border border-slate-700 transition-colors flex items-center gap-2 z-20"
            >
              {copied ? (
                <>
                  <svg className="w-3.5 h-3.5 text-teal-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
                  </svg>
                  <span>Copied!</span>
                </>
              ) : (
                <>
                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                  </svg>
                  <span>Copy JSON</span>
                </>
              )}
            </button>
            <pre className="bg-slate-950 p-6 rounded-xl border border-slate-800 text-teal-400 font-mono text-sm overflow-x-auto h-full">
              {JSON.stringify(data, null, 2)}
            </pre>
          </div>
        )}
      </div>
    </div>
  );
};

export default OutputPanel;

import React, { useState } from 'react';
import InputPanel from './components/InputPanel';
import OutputPanel from './components/OutputPanel';
import { analyzePrescription } from './services/geminiService';
import { PrescriptionData } from './types';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<PrescriptionData | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleAnalyze = async (base64: string, mimeType: string) => {
    setIsAnalyzing(true);
    setError(null);
    setData(null);

    try {
      const result = await analyzePrescription(base64, mimeType);
      setData(result);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred during analysis.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleReset = () => {
    setData(null);
    setError(null);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex flex-col md:flex-row h-screen w-full bg-slate-950 text-slate-200 overflow-hidden">
      {/* Left Input Panel */}
      <div className="w-full md:w-[450px] flex-shrink-0 border-r border-slate-800">
        <InputPanel 
          onAnalyze={handleAnalyze} 
          isLoading={isAnalyzing} 
          onReset={handleReset}
        />
      </div>

      {/* Right Output Panel */}
      <div className="flex-1 overflow-hidden relative">
        {isAnalyzing && (
          <div className="absolute inset-0 bg-slate-950/50 backdrop-blur-sm z-50 flex flex-col items-center justify-center space-y-6">
            <div className="relative">
              <div className="w-20 h-20 rounded-full border-4 border-slate-800 border-t-teal-500 animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                 <span className="text-teal-400">💊</span>
              </div>
            </div>
            <div className="text-center space-y-2">
              <h3 className="text-xl font-bold text-white">Reading Prescription</h3>
              <p className="text-slate-400 animate-pulse">Our AI is digitizing and interpreting medical instructions...</p>
            </div>
          </div>
        )}
        <OutputPanel data={data} error={error} />
      </div>
    </div>
  );
};

export default App;

