                  {item.data.patient_info.patient_name}
                </p>
                <p className="text-xs text-slate-400 truncate">
                  {item.data.doctor_info.clinic_name}
                </p>
                <p className="text-[10px] text-slate-500 mt-1">
                  {new Date(item.timestamp).toLocaleDateString()} • {new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default HistoryList;

import React, { useState, useRef } from 'react';
import { InputMode, HistoryItem } from '../types';
import HistoryList from './HistoryList';

interface InputPanelProps {
  onAnalyze: (base64: string, mimeType: string) => void;
  isLoading: boolean;
  onReset: () => void;
  history: HistoryItem[];
  onSelectHistory: (item: HistoryItem) => void;
  onClearHistory: () => void;
  onDeleteHistoryItem: (id: string) => void;
}

const InputPanel: React.FC<InputPanelProps> = ({ 
  onAnalyze, 
  isLoading, 
  onReset, 
  history, 
  onSelectHistory, 
  onClearHistory,
  onDeleteHistoryItem 
}) => {
  const [mode, setMode] = useState<InputMode>('upload');
  const [url, setUrl] = useState('');
  const [preview, setPreview] = useState<string | null>(null);
  const [selectedFile, setSelectedFile] = useState<{ base64: string; mimeType: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      setPreview(reader.result as string);
      setSelectedFile({ base64, mimeType: file.type });
    };
    reader.readAsDataURL(file);
  };

  const handleUrlBlur = async () => {
    if (!url) return;
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      const reader = new FileReader();
      reader.onload = () => {
        const base64 = (reader.result as string).split(',')[1];
        setPreview(reader.result as string);
        setSelectedFile({ base64, mimeType: blob.type });
      };
      reader.readAsDataURL(blob);
    } catch (err) {
      alert("Could not fetch image from URL. CORS or invalid link might be the cause.");
      console.error(err);
    }
  };

  const handleAnalyze = () => {
    if (selectedFile) {
      onAnalyze(selectedFile.base64, selectedFile.mimeType);
    } else {
      alert("Please provide a file or a valid image URL first.");
    }
  };

  const handleResetInternal = () => {
    setPreview(null);
    setSelectedFile(null);
    setUrl('');
    if (fileInputRef.current) fileInputRef.current.value = '';
    onReset();
  };

  return (
    <div className="flex flex-col h-full bg-slate-800/50 p-6 space-y-6">
      <div className="space-y-1">
        <h1 className="text-3xl font-bold text-teal-400 flex items-center gap-2">
          <span>💊</span> MediScan AI
        </h1>
        <p className="text-slate-400 text-sm">Medical Prescription Reader Dashboard</p>
      </div>

      <div className="bg-slate-900 rounded-xl p-1 flex overflow-hidden">
        <button
          onClick={() => setMode('upload')}
          className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${
            mode === 'upload' ? 'bg-teal-600 text-white' : 'text-slate-500 hover:text-slate-200'
          }`}
        >
          📁 UPLOAD
        </button>
        <button
          onClick={() => setMode('url')}
          className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${
            mode === 'url' ? 'bg-teal-600 text-white' : 'text-slate-500 hover:text-slate-200'
          }`}
        >
          🔗 URL
        </button>
        <button
          onClick={() => setMode('history')}
          className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${
            mode === 'history' ? 'bg-teal-600 text-white' : 'text-slate-500 hover:text-slate-200'
          }`}
        >
          📜 HISTORY
        </button>
      </div>

      <div className="flex-1 space-y-4 min-h-0">
        {mode === 'upload' && (
          <div 
            onClick={() => fileInputRef.current?.click()}
            className="border-2 border-dashed border-slate-700 hover:border-teal-500/50 rounded-xl p-8 flex flex-col items-center justify-center space-y-4 cursor-pointer transition-colors bg-slate-900/30"
          >
            <div className="bg-slate-800 p-4 rounded-full">
              <svg className="w-8 h-8 text-teal-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
              </svg>
            </div>
            <div className="text-center">
              <p className="text-slate-200 font-medium">Click to upload prescription</p>
              <p className="text-slate-500 text-xs mt-1">Supports JPG, PNG, PDF</p>
            </div>
            <input 
              type="file" 
              className="hidden" 
              ref={fileInputRef} 
              accept="image/*,application/pdf"
              onChange={handleFileChange}
            />
          </div>
        )}

        {mode === 'url' && (
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Image URL</label>
              <input
                type="text"
                placeholder="https://example.com/prescription.jpg"
                className="w-full bg-slate-900 border border-slate-700 rounded-lg px-4 py-3 text-slate-200 focus:outline-none focus:ring-2 focus:ring-teal-500/50"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                onBlur={handleUrlBlur}
              />
            </div>
          </div>
        )}

        {mode === 'history' && (
          <HistoryList 
            items={history} 
            onSelectItem={onSelectHistory} 
            onClearHistory={onClearHistory}
            onDeleteItem={onDeleteHistoryItem}
          />
        )}

        {mode !== 'history' && preview && (
          <div className="space-y-2">
            <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Preview</label>
            <div className="relative rounded-xl overflow-hidden border border-slate-700 aspect-video bg-black flex items-center justify-center">
              {selectedFile?.mimeType === 'application/pdf' ? (
                <div className="flex flex-col items-center text-slate-400">
                  <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 20 20"><path d="M4 4a2 2 0 012-2h4.586A2 2 0 0112 2.586L15.414 6A2 2 0 0116 7.414V16a2 2 0 01-2 2H6a2 2 0 01-2-2V4z"/></svg>
                  <span>PDF Document</span>
                </div>
              ) : (
                <img src={preview} alt="Preview" className="object-contain w-full h-full" />
              )}
            </div>
          </div>
        )}
      </div>

      <div className="space-y-3 pt-4 border-t border-slate-700/30">
        <button
          onClick={handleAnalyze}
          disabled={isLoading || !selectedFile || mode === 'history'}
          className={`w-full py-4 rounded-xl font-bold text-lg flex items-center justify-center gap-3 transition-all ${
            isLoading || !selectedFile || mode === 'history'
              ? 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-50'
              : 'bg-gradient-to-r from-teal-600 to-emerald-600 text-white shadow-lg shadow-teal-900/20 hover:scale-[1.02] active:scale-[0.98]'
          }`}
        >
          {isLoading ? (
            <>
              <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              <span>Analyzing...</span>
            </>
          ) : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span>Analyze Prescription</span>
            </>
          )}
        </button>
        <button
          onClick={handleResetInternal}
          className="w-full py-2 text-slate-400 text-xs hover:text-slate-200 transition-colors font-medium uppercase tracking-widest"
        >
          Clear and Reset
        </button>
      </div>
    </div>
  );
};

export default InputPanel;

import React, { useState, useEffect } from 'react';
import InputPanel from './components/InputPanel';
import OutputPanel from './components/OutputPanel';
import { analyzePrescription } from './services/geminiService';
import { PrescriptionData, HistoryItem } from './types';

const STORAGE_KEY = 'mediscan_rx_history';

const App: React.FC = () => {
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [data, setData] = useState<PrescriptionData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);

  // Load history on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (err) {
        console.error("Failed to load history", err);
      }
    }
  }, []);

  // Save history on change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(history));
  }, [history]);

  const handleAnalyze = async (base64: string, mimeType: string) => {
    setIsAnalyzing(true);
    setError(null);
    setData(null);

    try {
      const result = await analyzePrescription(base64, mimeType);
      setData(result);

      // Add to history
      const newHistoryItem: HistoryItem = {
        id: crypto.randomUUID(),
        timestamp: Date.now(),
        data: result
      };
      setHistory(prev => [newHistoryItem, ...prev].slice(0, 50)); // Limit to 50 items
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred during analysis.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleSelectHistoryItem = (item: HistoryItem) => {
    setData(item.data);
    setError(null);
  };

  const handleClearHistory = () => {
    if (window.confirm("Are you sure you want to clear your entire extraction history?")) {
      setHistory([]);
    }
  };

  const handleDeleteHistoryItem = (id: string) => {
    setHistory(prev => prev.filter(item => item.id !== id));
  };

  const handleReset = () => {
    setData(null);
    setError(null);
    setIsAnalyzing(false);
  };

  return (
    <div className="flex flex-col md:flex-row h-screen w-full bg-slate-950 text-slate-200 overflow-hidden">
      {/* Left Input Panel */}
      <div className="w-full md:w-[450px] flex-shrink-0 border-r border-slate-800">
        <InputPanel 
          onAnalyze={handleAnalyze} 
          isLoading={isAnalyzing} 
          onReset={handleReset}
          history={history}
          onSelectHistory={handleSelectHistoryItem}
          onClearHistory={handleClearHistory}
          onDeleteHistoryItem={handleDeleteHistoryItem}
        />
      </div>

      {/* Right Output Panel */}
      <div className="flex-1 overflow-hidden relative">
        {isAnalyzing && (
          <div className="absolute inset-0 bg-slate-950/50 backdrop-blur-sm z-50 flex flex-col items-center justify-center space-y-6">
            <div className="relative">
              <div className="w-20 h-20 rounded-full border-4 border-slate-800 border-t-teal-500 animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                 <span className="text-teal-400 text-2xl">💊</span>
              </div>
            </div>
            <div className="text-center space-y-2">
              <h3 className="text-xl font-bold text-white">Reading Prescription</h3>
              <p className="text-slate-400 animate-pulse">Our AI is digitizing and interpreting medical instructions...</p>
            </div>
          </div>
        )}
        <OutputPanel data={data} error={error} />
      </div>
    </div>
  );
};

export default App;
